# ---------------------------------------------------------------------------
# Bench state directory, concurrency-group locks, in-flight.json
# ---------------------------------------------------------------------------

bench_state_dir() {
  printf '%s\n' "${FIZEAU_BENCH_STATE_DIR:-${XDG_CACHE_HOME:-$HOME/.cache}/fizeau-benchmark}"
}

bench_lock_dir() { printf '%s/locks\n' "$(bench_state_dir)"; }

bench_host_id() { printf '%s\n' "${BENCH_HOSTNAME_OVERRIDE:-$(hostname)}"; }

bench_host_dir() { printf '%s/%s\n' "$(bench_state_dir)" "$(bench_host_id)"; }

bench_inflight_path() { printf '%s/in-flight.json\n' "$(bench_host_dir)"; }

bench_inflight_lock_path() { printf '%s/in-flight.lock\n' "$(bench_host_dir)"; }

ensure_state_dirs() {
  mkdir -p "$(bench_lock_dir)" "$(bench_host_dir)"
}

# profile_concurrency_group: extracts .concurrency_group from a profile YAML,
# falling back to "default" if unset. Used both for flock path and in-flight
# record-keeping.
profile_concurrency_group() {
  local file="$1"
  local g
  g="$(yq -o=json '.' "$file" 2>/dev/null | jq -r '.concurrency_group // "default"')"
  [[ -n "${g}" && "${g}" != "null" ]] || g="default"
  printf '%s\n' "${g}"
}

# concurrency_group_lock_file: per-group flock file path.
concurrency_group_lock_file() {
  printf '%s/%s.lock\n' "$(bench_lock_dir)" "$1"
}

# _inflight_locked_exec runs a callable while holding the in-flight.json lock.
_inflight_locked_exec() {
  ensure_state_dirs
  local fpath; fpath="$(bench_inflight_path)"
  local lock; lock="$(bench_inflight_lock_path)"
  [[ -f "${fpath}" ]] || printf '%s\n' '{"cells":[]}' >"${fpath}"
  (
    exec 9>"${lock}"
    flock 9
    "$@"
  )
}

# Prune entries whose pid is no longer alive. Caller must hold the lock.
_inflight_prune_locked() {
  local fpath; fpath="$(bench_inflight_path)"
  [[ -f "${fpath}" ]] || { printf '%s\n' '{"cells":[]}' >"${fpath}"; return 0; }
  local cells n i kept c pid
  cells="$(jq -c '.cells // []' "${fpath}" 2>/dev/null || printf '%s' '[]')"
  n="$(jq 'length' <<<"${cells}")"
  kept='[]'
  i=0
  while (( i < n )); do
    c="$(jq -c ".[$i]" <<<"${cells}")"
    pid="$(jq -r '.pid // 0' <<<"${c}")"
    if [[ "${pid}" -gt 0 ]] && kill -0 "${pid}" 2>/dev/null; then
      kept="$(jq -c --argjson c "${c}" '. + [$c]' <<<"${kept}")"
    fi
    i=$((i + 1))
  done
  local tmp; tmp="$(mktemp)"
  jq -n --argjson cs "${kept}" '{cells:$cs}' >"${tmp}"
  mv "${tmp}" "${fpath}"
}

_inflight_add_locked() {
  local entry="$1"
  _inflight_prune_locked
  local fpath; fpath="$(bench_inflight_path)"
  local tmp; tmp="$(mktemp)"
  jq --argjson e "${entry}" '.cells = ((.cells // []) + [$e])' "${fpath}" >"${tmp}"
  mv "${tmp}" "${fpath}"
}

_inflight_remove_locked() {
  local cell_id="$1"
  local fpath; fpath="$(bench_inflight_path)"
  [[ -f "${fpath}" ]] || return 0
  local tmp; tmp="$(mktemp)"
  jq --arg cid "${cell_id}" \
    '.cells = ((.cells // []) | map(select(.cell_id != $cid)))' \
    "${fpath}" >"${tmp}"
  mv "${tmp}" "${fpath}"
}

_inflight_read_locked() {
  _inflight_prune_locked
  cat "$(bench_inflight_path)"
}

inflight_add() { _inflight_locked_exec _inflight_add_locked "$1"; }
inflight_remove() { _inflight_locked_exec _inflight_remove_locked "$1"; }
inflight_read() { _inflight_locked_exec _inflight_read_locked; }
inflight_prune() { _inflight_locked_exec _inflight_prune_locked; }
inflight_count() { inflight_read | jq -r '(.cells // []) | length'; }

